sql.if:
and (a.buy_company_name like CONCAT('%',#{companyName},'%')
or a.sell_company_name like CONCAT('%',#{companyName},'%')
)

mapper.select:
SELECT s.sell_match_user_name userName, s.sell_match_user_id userId, DATE_FORMAT(s.created_date, '%Y-%m') createdDate, SUM(IF(s.match_credit_flg = TRUE, s.sell_total_amount, 0)) AS sellMoney,
SUM(IF(s.match_credit_flg = TRUE, (IFNULL(s.sell_total_amount, 0) - IFNULL(s.buy_total_amount, 0) - IFNULL(s.warehouse_amount, 0) - IFNULL(s.transport_amount, 0) - IFNULL(s.delivery_fee, 0) - IFNULL(s.financial_service_amount, 0) - IFNULL(s.sell_head_commission_amount, 0) - IFNULL(s.buy_head_commission_amount, 0) - IFNULL(s.sell_match_amount, 0) - IFNULL(s.buy_match_amount, 0)), 0)) sellMoneyProfit,
SUM(IF(s.match_credit_flg = FALSE, s.sell_total_amount, 0)) buyMoney,
SUM(IF(s.match_credit_flg = FALSE, (IFNULL(s.sell_total_amount, 0) - IFNULL(s.buy_total_amount, 0) - IFNULL(s.warehouse_amount, 0) - IFNULL(s.transport_amount, 0) - IFNULL(s.delivery_fee, 0) - IFNULL(s.sell_head_commission_amount, 0) - IFNULL(s.buy_head_commission_amount, 0) - IFNULL(s.sell_match_amount, 0) - IFNULL(s.buy_match_amount, 0)), 0)) buyMoneyProfit,
SUM(IF(s.match_credit_flg = TRUE, (IFNULL(s.sell_total_amount, 0) - IFNULL(s.buy_total_amount, 0) - IFNULL(s.warehouse_amount, 0) - IFNULL(s.transport_amount, 0) - IFNULL(s.delivery_fee, 0) - IFNULL(s.financial_service_amount, 0) - IFNULL(s.sell_head_commission_amount, 0) - IFNULL(s.buy_head_commission_amount, 0) - IFNULL(s.sell_match_amount, 0) - IFNULL(s.buy_match_amount, 0)), (IFNULL(s.sell_total_amount, 0) - IFNULL(s.buy_total_amount, 0) - IFNULL(s.warehouse_amount, 0) - IFNULL(s.transport_amount, 0) - IFNULL(s.delivery_fee, 0) - IFNULL(s.sell_head_commission_amount, 0) - IFNULL(s.buy_head_commission_amount, 0) - IFNULL(s.sell_match_amount, 0) - IFNULL(s.buy_match_amount, 0)))) AS sumProfitMoney FROM t_ctr_contract_settlement s join t_ctr_contract c on c.id =s.sell_contract_id and c.status !='C'
DATE_FORMAT(s.created_date, '%Y-%m') = #{yearAndMonth}
and DATE_FORMAT(s.created_date, '%Y') = #{year}
and DATE_FORMAT(s.created_date, '%m') between #{startMonth} and #{endMonth}
and s.sell_match_user_id = #{userId}
and s.sell_match_user_id in
#{userIds[${index}]}
GROUP BY s.sell_match_user_id
